long long solve(long long n, vector<vector<long long>> edges, long long k) {
    // sort edges by weight
    sort(edges.begin(), edges.end(), [](const auto& a, const auto& b) { return a[2] < b[2]; });
    // binary search
    long long low = 0;
    long long high = edges.empty() ? 0 : edges.back()[2];
    long long answer = high;
    while (low <= high) {
        long long mid = (low + high) / 2;
        // find the number of edges with weight <= mid
        int idx = upper_bound(edges.begin(), edges.end(), mid, [](const auto& e) { return e[2]; }) - edges.begin();
        DSU dsu(n);
        for (int i = 0; i < idx; ++i) {
            dsu.union(edges[i][0], edges[i][1]);
        }
        int components = dsu.get_count();
        if (components <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return answer;
}

