using namespace std;

class DSU {
private:
    vector<int> parent;
    vector<int> rank;
    int count;
public:
    DSU(int n) {
        parent.resize(n);
        rank.resize(n, 0);
        for (int i = 0; i < n; ++i) parent[i] = i;
        count = n;
    }
    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }
    void union(int x, int y) {
        int x_root = find(x);
        int y_root = find(y);
        if (x_root == y_root) return;
        if (rank[x_root] < rank[y_root]) {
            parent[x_root] = y_root;
        } else {
            parent[y_root] = x_root;
            if (rank[x_root] == rank[y_root]) {
                rank[x_root]++;
            }
        }
        count--;
    }
    int get_count() {
        return count;
    }
};

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    if (edges.empty()) {
        return 0;
    }
    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });
    vector<long long> weights;
    for (const auto& e : edges) {
        weights.push_back(e[2]);
    }
    long long low = 0;
    long long high = weights.back();
    long long answer = high;
    while (low <= high) {
        long long mid = (low + high) / 2;
        auto it = upper_bound(weights.begin(), weights.end(), mid);
        int idx = it - weights.begin();
        DSU dsu(n);
        for (int i = 0; i < idx; ++i) {
            int u = edges[i][0];
            int v = edges[i][1];
            dsu.union(u, v);
        }
        int components = dsu.get_count();
        if (components <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return answer;
}
