import bisect

class DSU:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n
        self.count = n  # Number of connected components

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        x_root = self.find(x)
        y_root = self.find(y)
        if x_root == y_root:
            return
        if self.rank[x_root] < self.rank[y_root]:
            self.parent[x_root] = y_root
        else:
            self.parent[y_root] = x_root
            if self.rank[x_root] == self.rank[y_root]:
                self.rank[x_root] += 1
        self.count -= 1

    def get_count(self):
        return self.count

def solve(n: int, edges: list[list[int]], k: int) -> int:
    if not edges:
        return 0
    sorted_edges = sorted(edges, key=lambda x: x[2])
    weights = [e[2] for e in sorted_edges]
    max_weight = weights[-1]

    low = 0
    high = max_weight
    answer = max_weight

    while low <= high:
        mid = (low + high) // 2
        idx = bisect.bisect_right(weights, mid)
        dsu = DSU(n)
        for u, v, w in sorted_edges[:idx]:
            dsu.union(u, v)
        components = dsu.get_count()
        if components <= k:
            answer = mid
            high = mid - 1
        else:
            low = mid + 1
    return answer
